#include <vector>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* Zero y[] and tmp[] once (OpenMP reduces! but the compiler can
       still serialise these small loops). */
    #pragma omp parallel for
    for (int j = 0; j < n; ++j) y[j] = 0.0;
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) tmp[i] = 0.0;

    /* Use cache‑friendly pointer access and accumulate in registers. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double* Ai = A[i].data();
        double Ti = 0.0;
        for (int j = 0; j < n; ++j)
            Ti += Ai[j] * x[j];
        tmp[i] = Ti;

        /* Update y atomically with a critical section per element
           (the inner loop is small, so simple addition with
           omp atomic works fine). */
        for (int j = 0; j < n; ++j) {
            #pragma omp atomic
            y[j] += Ai[j] * Ti;
        }
    }
}
