void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Get raw pointers for cache‑friendly access
    const std::size_t * L_offsets = reinterpret_cast<const std::size_t *>(L.data()); // unused, but keep for consistency
    const std::vector<double> *L_rows = L.data();

    double *xs = x.data();
    const double *bs = b.data();

    for (int i = 0; i < n; ++i) {
        double sum = bs[i];
        const std::vector<double> &row = L_rows[i];
        const double *rowp = row.data();
        for (int j = 0; j < i; ++j) {
            sum -= rowp[j] * xs[j];
        }
        xs[i] = sum / rowp[i];
    }
