/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    // obtain raw pointers to the underlying contiguous storage
    // (assumes each inner vector is contiguous and has size >= m or n)
    double *c = C[0].data();   // C is MxN
    double *a = A[0].data();   // A is MxM
    double *b = B[0].data();   // B is MxN

#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double bj = b[i * n + j];          // B[i][j]
            double aik = a[i * m + i];         // A[i][i]
            for (int k = 0; k < i; ++k) {
                double aikk = a[i * m + k];    // A[i][k]
                c[k * n + j] += alpha * bj * aikk;    // C[k][j] += ...
                temp2 += b[k * n + j] * aikk;          // temp2 += ...
            }
            c[i * n + j] = beta * c[i * n + j] + alpha * bj * aik + alpha * temp2;
        }
    }
}
