/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B)
{
    // Pre‑compute the constant factor
    const double coeff = 0.33333;     // 1/3 ≈ 0.33333333333

    // Obtain raw pointers for fast access; the vectors are guaranteed
    // to be contiguous, so this is safe.
    double* restrict a = A.data();
    double* restrict b = B.data();

    // Main time‑step loop (cannot be parallelised due to data dependencies)
    for (int t = 0; t < tsteps; ++t)
    {
        /* First sweep: compute B from A
         * Each iteration is independent, so we can parallelise the loop.
         * We skip the first and last elements to preserve the boundary
         * conditions and avoid race conditions with the `-1` and `+1`
         * accesses.
         */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second sweep: compute A from B
         * Again, each iteration is independent.
         */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
