#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Convert the 2‑D std::vector layout into a flat pointer
    double* const a[ni];
    double* const b[nk];
    double* const c[ni];

    for (int i = 0; i < ni; ++i) a[i] = A[i].data();
    for (int k = 0; k < nk; ++k) b[k] = B[k].data();
    for (int i = 0; i < ni; ++i) c[i] = C[i].data();

    // Parallelise over the outermost loop
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // Scale the i‑th row of C by beta
        double* ci = c[i];
        for (int j = 0; j < nj; ++j) ci[j] *= beta;

        // Block over k for better cache locality
        const int K_BLOCK = 32;        // tuned for modern L2 cache (≈256 KB)
        const int N_BLOCK = 64;        // L2 reuse of B

        for (int k = 0; k < nk; k += K_BLOCK) {
            int k_end = (k + K_BLOCK < nk) ? k + K_BLOCK : nk;
            for (int kk = k; kk < k_end; ++kk) {
                const double aik = alpha * a[i][kk];
                double* bj = b[kk];
                // Inner loop over j in blocks
                for (int jj = 0; jj < nj; jj += N_BLOCK) {
                    int j_end = (jj + N_BLOCK < nj) ? jj + N_BLOCK : nj;
                    for (int j = jj; j < j_end; ++j) {
                        ci[j] += aik * bj[j];
                    }
                }
            }
        }
    }
}
