/* Main computational kernel. The function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    /* Reduce repeated object‑member lookups by using short references
       and local variables. Each row is a contiguous std::vector<double> */
    for (int i = 0; i < n; ++i) {
        double* rowi = A[i].data();          // pointer to the i‑th row

        /* Off‑diagonal elements A[i][j] (j < i) */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;                // accumulates A[i][k] * A[j][k]
            double* rowj = A[j].data();      // pointer to the j‑th row
            for (int k = 0; k < j; ++k) {
                sum += rowi[k] * rowj[k];
            }
            rowi[j] = (rowi[j] - sum) / rowj[j];
        }

        /* Diagonal element A[i][i] */
        double sum = 0.0;
        for (int k = 0; k < i; ++k)
            sum += rowi[k] * rowi[k];
        rowi[i] = std::sqrt(rowi[i] - sum);
    }
}
