/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<double>>& C4,
		    std::vector<double>& /*sum_unused*/) {

    // Allocate a temporary sum buffer once.  It will be reused for all (r,q,p)
    std::vector<double> sum(np);

    // Parallelise the outer two loops with OpenMP.
    // Using collapse(2) distributes tiles of (r,q) across threads.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q) {
            // Row A[r][q] is a std::vector<double> of length np.
            // Access it as a contiguous block for performance.
            double *Apr = A[r][q].data();

            // C4 is already a contiguous 2D array in column-major order
            // where C4[s][p] means s is row, p is column, both dimensions np.
            // Obtain pointers for each column p for quick access.
            const double *C4col[np];
            for (int p = 0; p < np; ++p)
                C4col[p] = &C4[p][0];   // C4[p][s] will be used as row p

            // For each output element p, compute the dot product of
            // row A[r][q] with column p of C4.
            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                const double *C4p = C4col[p];
                // Inner s‑loop can be vectorised by the compiler.
                for (int s = 0; s < np; ++s)
                    acc += Apr[s] * C4p[s];
                sum[p] = acc;
            }

            // Write back the result to A[r][q][p].
            for (int p = 0; p < np; ++p)
                Apr[p] = sum[p];
        }
}
