#include <vector>
#include <cstddef>
#include <omp.h>

/* Helper to convert std::vector<std::vector<double>> into a flat array view */
struct MatrixView {
    double* data;
    std::size_t stride;   // number of columns

    constexpr double& operator()(std::size_t i, std::size_t j) const {
        return data[i * stride + j];
    }
};

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {
    // Create a flat view of the 2‑D matrix for faster indexing
    MatrixView mat{A[0].data(), static_cast<std::size_t>(n)};

    /* ---------- LU Decomposition (Doolittle) ---------- */
    for (int i = 0; i < n; ++i) {
        /* --- L part (j < i) --- */
        for (int j = 0; j < i; ++j) {
            double w = mat(i, j);
#pragma ivdep
            for (int k = 0; k < j; ++k) {
                w -= mat(i, k) * mat(k, j);
            }
            mat(i, j) = w / mat(j, j);
        }

        /* --- U part (j >= i) --- */
        for (int j = i; j < n; ++j) {
            double w = mat(i, j);
#pragma ivdep
            for (int k = 0; k < i; ++k) {
                w -= mat(i, k) * mat(k, j);
            }
            mat(i, j) = w;
        }
    }

    /* ---------- Forward substitution y = L⁻¹ b ---------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double w = b[i];
#pragma ivdep
        for (int j = 0; j < i; ++j) {
            w -= mat(i, j) * y[j];
        }
        y[i] = w;
    }

    /* ---------- Backward substitution x = U⁻¹ y ---------- */
#pragma omp parallel for schedule(static) collapse(1)
    for (int ii = n - 1; ii >= 0; --ii) {
        int i = ii;
        double w = y[i];
#pragma ivdep
        for (int j = i + 1; j < n; ++j) {
            w -= mat(i, j) * x[j];
        }
        x[i] = w / mat(i, i);
    }
}
