/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {

    /* Zero‑out s in parallel */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        s[i] = 0.0;
    }

    /* Compute s and q */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double r_i = r[i];
        double sum_q = 0.0;
        for (int j = 0; j < m; ++j) {
            double a = A[i][j];
            sum_q += a + p[j];
            /* Accumulate into s[j] atomically to avoid race conditions */
            #pragma omp atomic
            s[j] += r_i * a;
        }
        q[i] = sum_q;
    }
}
