/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    // 1. Update matrix A
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        std::vector<double> *row = &A[i];
        double* Arow = row->data();
        for (int j = 0; j < n; ++j) {
            Arow[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // 2. Compute x += beta * Aᵀ * y
    // accumulate in a temporary array to avoid repetitive writes
    std::vector<double> x_tmp(n, 0.0);
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        double yj = y[j];
        for (int i = 0; i < n; ++i) {
            x_tmp[i] += beta * A[i][j] * yj;
        }
    }
    for (int i = 0; i < n; ++i)
        x[i] += x_tmp[i];

    // 3. x += z
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        x[i] += z[i];

    // 4. w += alpha * A * x
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ai = alpha * x[i];
        std::vector<double> *row = &A[i];
        const double* Arow = row->data();
        for (int j = 0; j < n; ++j) {
            w[i] += ai * Arow[j];
        }
    }
}
