#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A)
{
    // Treat A as a single contiguous block: A[i][j] == A[i*n + j]
    const std::size_t nn = static_cast<std::size_t>(n) * static_cast<std::size_t>(n);
    double* base = reinterpret_cast<double*>(const_cast<std::vector<double>*>(&A[0])->data());

    constexpr double inv9 = 1.0 / 9.0;

    for (int t = 0; t < tsteps; ++t)
    {
        /* Parallelise the outer spatial loops; two loops are collapsed
           to give more work units for each thread, improving load balance
           and hiding memory latency. */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= n - 2; ++i)
        {
            const std::size_t i_off = static_cast<std::size_t>(i) * static_cast<std::size_t>(n);
            const std::size_t i_minus = i_off - static_cast<std::size_t>(n);     // i-1
            const std::size_t i_plus  = i_off + static_cast<std::size_t>(n);     // i+1

            for (int j = 1; j <= n - 2; ++j)
            {
                const std::size_t idx = i_off + static_cast<std::size_t>(j);
                const double sum =
                    base[i_minus + j - 1] + // (i-1, j-1)
                    base[i_minus + j]     + // (i-1, j)
                    base[i_minus + j + 1] + // (i-1, j+1)
                    base[ i_off  + j - 1] + // (i,   j-1)
                    base[ i_off  + j]     + // (i,   j)
                    base[ i_off  + j + 1] + // (i,   j+1)
                    base[i_plus  + j - 1] + // (i+1, j-1)
                    base[i_plus  + j]     + // (i+1, j)
                    base[i_plus  + j + 1];  // (i+1, j+1)

                base[idx] = sum * inv9;
            }
        }
    }
}
