/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    for (int i = 0; i < n; ++i) {
        // First part – compute sub‑diagonal elements (j < i)
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < i; ++j) {
            double sum = A[i][j];
            // Unroll inner loop for a few iterations
            int k = 0;
            int lim = j;
            for (; k + 3 < lim; k += 4) {
                sum -= A[i][k]   * A[k][j];
                sum -= A[i][k+1] * A[k+1][j];
                sum -= A[i][k+2] * A[k+2][j];
                sum -= A[i][k+3] * A[k+3][j];
            }
            for (; k < lim; ++k) {
                sum -= A[i][k] * A[k][j];
            }
            A[i][j] = sum / A[j][j];
        }

        // Second part – compute the rest of the row (j ≥ i)
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double sum = A[i][j];
            int k = 0;
            int lim = i;
            for (; k + 3 < lim; k += 4) {
                sum -= A[i][k]   * A[k][j];
                sum -= A[i][k+1] * A[k+1][j];
                sum -= A[i][k+2] * A[k+2][j];
                sum -= A[i][k+3] * A[k+3][j];
            }
            for (; k < lim; ++k) {
                sum -= A[i][k] * A[k][j];
            }
            A[i][j] = sum;
        }
    }
}
