        for (int i = 0; i < nx; ++i) {
            double* ex_i   = ex_rows[i];
            double* hz_i   = hz_rows[i];
            for (int j = 1; j < ny; ++j) {
                ex_i[j] -= 0.5 * (hz_i[j] - hz_i[j-1]);
            }
        }

        /* 4. Update hz[i][j] for interior cells */
        for (int i = 0; i < nx-1; ++i) {
            double* hz_i   = hz_rows[i];
            double* hz_i1  = hz_rows[i+1];
            double* ex_i   = ex_rows[i];
            double* ey_i   = ey_rows[i];
            double* ey_i1  = ey_rows[i+1];
            for (int j = 0; j < ny-1; ++j) {
                hz_i[j] -= 0.7 * (ex_i[j+1] - ex_i[j] + ey_i1[j] - ey_i[j]);
