/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    /* Flatten A and C into contiguous arrays for high‑performance
       access.  The original vectors are left untouched except for the
       final copy back. */
    const std::size_t sizeA  = static_cast<std::size_t>(n) * m;
    const std::size_t sizeC  = static_cast<std::size_t>(n) * n;
    std::vector<double> aFlat(sizeA);
    std::vector<double> cFlat(sizeC);

    /* Copy data into the flat arrays. */
    for (int i = 0; i < n; ++i) {
        std::memcpy(&aFlat[static_cast<std::size_t>(i) * m], A[i].data(), m * sizeof(double));
        std::memcpy(&cFlat[static_cast<std::size_t>(i) * n], C[i].data(), n * sizeof(double));
    }

    /* Core computation:  C := alpha*A*Aᵀ + beta*C.
       Only the lower triangular part is updated, the rest of C is kept
       unchanged (as was the case originally). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const std::size_t idx_i = static_cast<std::size_t>(i) * n;
        for (int j = 0; j <= i; ++j) {
            cFlat[idx_i + j] *= beta;            // C[i][j] *= beta
        }

        const std::size_t idx_i_a = static_cast<std::size_t>(i) * m;
        for (int k = 0; k < m; ++k) {
            double aik = aFlat[idx_i_a + k];
            for (int j = 0; j <= i; ++j) {
                cFlat[idx_i + j] += alpha * aik * aFlat[static_cast<std::size_t>(j) * m + k];
            }
        }
    }

    /* Copy the result back into the original 2‑D vector structure. */
    for (int i = 0; i < n; ++i) {
        std::memcpy(C[i].data(), &cFlat[static_cast<std::size_t>(i) * n], n * sizeof(double));
    }
}
