/*                           std::vector<double>& tmp,                        */
/*                           std::vector<double>& x,                           */
/*                           std::vector<double>& y);                         */
/*------------------------------------------------------------------------------*/

void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* We treat each row of A and B as a contiguous block of memory.
       The input containers are assumed to be 2‑D square matrices
       of size n × n; the API guarantees that each inner vector
       has a size of n. */
    const std::size_t stride = static_cast<std::size_t>(n);

#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double ti   = 0.0;
        double yi   = 0.0;
        const double *ap = &A[i][0];
        const double *bp = &B[i][0];
        const double *xp = &x[0];

        /* Loop unroll for better vectorisation */
        int j = 0;
        // Unroll by 4
        for (; j <= n - 4; j += 4) {
            ti += ap[j  ] * xp[j  ];
            ti += ap[j+1] * xp[j+1];
            ti += ap[j+2] * xp[j+2];
            ti += ap[j+3] * xp[j+3];

            yi += bp[j  ] * xp[j  ];
            yi += bp[j+1] * xp[j+1];
            yi += bp[j+2] * xp[j+2];
            yi += bp[j+3] * xp[j+3];
        }
        // Tail
        for (; j < n; ++j) {
            ti += ap[j] * xp[j];
            yi += bp[j] * xp[j];
        }

        yi = alpha * ti + beta * yi;
        tmp[i] = ti;
        y[i] = yi;
    }
}
```
**Key optimisation points**

1. **Manual memory layout** –  `&A[i][0]` and `&B[i][0]` give contiguous pointers per row, enabling vectorised loads.
2. **OpenMP parallelism** –  outer loop (rows) is distributed statically among the 8 threads.
3. **Loop unrolling** –  unroll inner product by 4 to reduce loop‑control overhead and improve instruction‑level parallelism.
4. **Register temporaries** –  `ti` and `yi` are local registers inside the thread’s iteration.  
5. **Minimal overhead** –  the algorithmic work remains unchanged; only the low‑level execution path is optimised.

