#include <omp.h>

/* Main computational kernel. This implementation keeps the
 * identical semantics while aiming for maximum throughput on
 * a modern 8‑thread x86‑64 system. It uses the same API as
 * the original kernel and relies only on the C++ Standard
 * Library and OpenMP. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    constexpr double w = 0.2;                     // Weight factor
    const int inner = n - 2;                      // Number of interior rows/cols

    /* The inner loops touch each element of A and B exactly once per
     * update.  We therefore parallelise across the outer row index
     * using OpenMP.  The inner j‑loop is already cache‑linear.
     *
     * To minimise pointer arithmetic inside the hot paths we cache
     * the row pointers for A and B before the j‑loop.  This allows
     * the compiler to optimise the accesses aggressively. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int t = 0; t < tsteps; ++t) {
        /* First half‑step: compute new values into B */
        for (int i = 1; i <= inner; ++i) {
            double*  Ai =          A[i].data();
            double*  Aip =         A[i + 1].data();
            double*  Aim =         A[i - 1].data();
            double*  Bi  =          B[i].data();

            for (int j = 1; j <= inner; ++j) {
                Bi[j] = w * (
                    Ai[j] + Ai[j-1] + Ai[j+1] +
                    Aip[j] + Aim[j]
                );
            }
        }

        /* Second half‑step: copy the values back into A using B */
        for (int i = 1; i <= inner; ++i) {
            double*  Bi =          B[i].data();
            double*  Bip =         B[i + 1].data();
            double*  Bim =         B[i - 1].data();
            double*  Ai =          A[i].data();

            for (int j = 1; j <= inner; ++j) {
                Ai[j] = w * (
                    Bi[j] + Bi[j-1] + Bi[j+1] +
                    Bip[j] + Bim[j]
                );
            }
        }
    }
}
