#include <cmath>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    constexpr double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- mean ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += data[i][j];
        mean[j] = sum / n;
    }

    /* ---------- stddev ---------- */
    std::vector<double> var(m, 0.0);
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        double pivot = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - pivot;
            s += d * d;
        }
        var[j] = s / n;
    }

    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double d = std::sqrt(var[j]);
        stddev[j] = d <= eps ? 1.0 : d;
    }

    /* ---------- normalize data ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double>& row = data[i];
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
            row[j] *= inv_sqrt_n / stddev[j];
        }
    }

    /* ---------- correlation ---------- */
    // initialise diagonal to 1.0
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
        corr[i][i] = 1.0;

    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k)
                s += data[k][i] * data[k][j];
            corr[i][j] = s;
            corr[j][i] = s;
        }
    }
}
