/*
 * Computes the mean vector, subtracts it from the data matrix and then
 * builds the covariance matrix. The input data and covariance matrices are
 * stored in row‑major order as std::vector<std::vector<double>> but the
 * implementation converts them into a single contiguous array to enable
 * cache‑friendly access and vectorisation.
 *
 * The output is written back into the original 2‑D containers, preserving
 * their layout.
 */
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // Reshape data into a contiguous buffer (row‑major)
    std::vector<double> flat_data(static_cast<std::size_t>(n) * m);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            flat_data[static_cast<std::size_t>(i) * m + j] = data[i][j];
        }
    }

    // Compute column means
    std::vector<double> col_mean(m, 0.0);
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += flat_data[static_cast<std::size_t>(i) * m + j];
        }
        col_mean[j] = s / n;
        mean[j] = col_mean[j];
    }

    // Subtract means from the data
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = &flat_data[static_cast<std::size_t>(i) * m];
        for (int j = 0; j < m; ++j) {
            row[j] -= col_mean[j];
        }
    }

    // Compute covariance matrix (upper‑triangular, then mirror)
    // We use manual block‑size parallelization to keep the inner
    // accumulation loop in a single thread for efficient vectorisation.
    const int block = 32;                // block size for the outer index i
    #pragma omp parallel for schedule(static)
    for (int i_block = 0; i_block < m; i_block += block) {
        int i_end = std::min(i_block + block, m);
        for (int i = i_block; i < i_end; ++i) {
            for (int j = i; j < m; ++j) {
                double sum = 0.0;
                for (int k = 0; k < n; ++k) {
                    sum += flat_data[static_cast<std::size_t>(k) * m + i] *
                           flat_data[static_cast<std::size_t>(k) * m + j];
                }
                sum /= (n - 1.0);
                cov[i][j] = sum;
                cov[j][i] = sum;          // mirror
            }
        }
    }

    // Write back the centered data into the original matrix
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = flat_data[static_cast<std::size_t>(i) * m + j];
        }
    }
}
