#include <vector>
#include <cmath>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* pointers to the underlying contiguous data.
       The input vectors are assumed to be row‑major and
       each row is a contiguous sub‑vector.                */
    double *Eptr = &E[0][0];
    const double *Aptr = &A[0][0];
    const double *Bptr = &B[0][0];
    double *Fptr = &F[0][0];
    const double *Cptr = &C[0][0];
    const double *Dptr = &D[0][0];
    double *Gptr = &G[0][0];

    /* ------------------------------------------------------------------
       1st stage :  E = A * B   (ni × nj  =  ni × nk  *  nk × nj)
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *Erow = Eptr + i * nj;
        const double *Arow = Aptr + i * nk;
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double *Bcol = Bptr + j;
            for (int k = 0; k < nk; ++k) {
                sum += Arow[k] * Bcol[k * nj];
            }
            Erow[j] = sum;
        }
    }

    /* ------------------------------------------------------------------
       2nd stage :  F = C * D   (nj × nl  =  nj × nm  *  nm × nl)
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double *Frow = Fptr + i * nl;
        const double *Crow = Cptr + i * nm;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double *Dcol = Dptr + j;
            for (int k = 0; k < nm; ++k) {
                sum += Crow[k] * Dcol[k * nl];
            }
            Frow[j] = sum;
        }
    }

    /* ------------------------------------------------------------------
       3rd stage :  G = E * F   (ni × nl  =  ni × nj  *  nj × nl)
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *Grow = Gptr + i * nl;
        const double *Erow = Eptr + i * nj;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double *Fcol = Fptr + j;
            for (int k = 0; k < nj; ++k) {
                sum += Erow[k] * Fcol[k * nl];
            }
            Grow[j] = sum;
        }
    }
}
