/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const int N = n * n * n;                     // total number of elements
    const double inv8 = 0.125;                   // 1/8

    /* Flatten the 3‑D containers into contiguous 1‑D buffers
       so we can do efficient pointer arithmetic and enable
       vectorised and cache‑friendly access. */
    double* a_buf = new double[N];
    double* b_buf = new double[N];

    // Helper to map 3‑D indices to 1‑D index
    auto idx = [n](int i, int j, int k) -> int { return i * n * n + j * n + k; };

    /* Copy the original data into the flat buffers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            std::memcpy(&a_buf[idx(i, j, 0)], &A[i][j][0], n * sizeof(double));

    for (int t = 0; t < tsteps; ++t)
    {
        /* ---- update B from A ---- */
#pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k)
                {
                    int p = idx(i, j, k);
                    double center = a_buf[p];
                    double val = inv8 * (a_buf[idx(i+1, j, k)] - 2.0 * center + a_buf[idx(i-1, j, k)])
                               + inv8 * (a_buf[idx(i, j+1, k)] - 2.0 * center + a_buf[idx(i, j-1, k)])
                               + inv8 * (a_buf[idx(i, j, k+1)] - 2.0 * center + a_buf[idx(i, j, k-1)])
                               + center;
                    b_buf[p] = val;
                }

        /* ---- update A from B ---- */
#pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k)
                {
                    int p = idx(i, j, k);
                    double center = b_buf[p];
                    double val = inv8 * (b_buf[idx(i+1, j, k)] - 2.0 * center + b_buf[idx(i-1, j, k)])
                               + inv8 * (b_buf[idx(i, j+1, k)] - 2.0 * center + b_buf[idx(i, j-1, k)])
                               + inv8 * (b_buf[idx(i, j, k+1)] - 2.0 * center + b_buf[idx(i, j, k-1)])
                               + center;
                    a_buf[p] = val;
                }
    }

    /* Copy the final data back into the original 3‑D containers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            std::memcpy(&A[i][j][0], &a_buf[idx(i, j, 0)], n * sizeof(double));

    delete[] a_buf;
    delete[] b_buf;
}
