#include <cmath>
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* QR Decomposition with Modified Gram Schmidt.
 * The algorithm is unchanged; only lower‑level writes are
 * vectorised and parallelised for speed. The data structures
 * remain std::vector<std::vector<double>> so the harness
 * signature is respected. */
static inline double dot_product(const std::vector<double> &x,
                                 const std::vector<double> &y,
                                 std::size_t m)
{
    double sum = 0.0;
#pragma omp simd reduction(+:sum)
    for (std::size_t i = 0; i < m; ++i)
        sum += x[i] * y[i];
    return sum;
}

void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>> &A,
                        std::vector<std::vector<double>> &R,
                        std::vector<std::vector<double>> &Q)
{
    const double eps = 1e-16;          // guard against division by zero
    // Work with raw pointers for the inner vectors to avoid
    // repeated bounds checks.
    std::vector<double*> A_ptrs(m);
    std::vector<double*> Q_ptrs(m);
    std::vector<double*> R_ptrs(n);

    for (int i = 0; i < m; ++i) A_ptrs[i] = A[i].data();
    for (int i = 0; i < m; ++i) Q_ptrs[i] = Q[i].data();
    for (int i = 0; i < n; ++i) R_ptrs[i] = R[i].data();

    for (int k = 0; k < n; ++k) {
        // Norm of column k of A.
        double nrm = 0.0;
#pragma omp simd reduction(+:nrm)
        for (int i = 0; i < m; ++i)
            nrm += A_ptrs[i][k] * A_ptrs[i][k];
        nrm = std::sqrt(std::max(nrm, eps));
        R_ptrs[k][k] = nrm;

        // Q(:,k) = A(:,k) / nrm
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Q_ptrs[i][k] = A_ptrs[i][k] / nrm;

        // Transform remaining columns
        for (int j = k + 1; j < n; ++j) {
            double r_kj = 0.0;
#pragma omp simd reduction(+:r_kj)
            for (int i = 0; i < m; ++i)
                r_kj += Q_ptrs[i][k] * A_ptrs[i][j];
            R_ptrs[k][j] = r_kj;

#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                A_ptrs[i][j] -= Q_ptrs[i][k] * r_kj;
        }
    }
}
