```cpp
#include <algorithm>
#include <cstddef>
#include <cstdlib>
#include <vector>
#include <omp.h>

/*  Optimised Nussinov kernel.
 *  The interface matches the original benchmark: `n` is the length of the
 *  sequence, `seq` contains the nucleotide code (0…3) and `table` is a
 *  square `n × n` matrix that will be filled in-place.
 *
 *  The implementation:
 *      – uses a single contiguous array for the DP table to take advantage
 *        of cache friendliness and to eliminate the indirection cost of
 *        std::vector of vectors.
 *      – employs a constant‑time inline match predicate.
 *      – parallelises over the anti‑diagonals (i+j constant) so that each
 *        thread works on independent rows, avoiding data races.
 *      – uses a small loop unrolling for the k‑loop to further reduce
 *        branching and increase SIMD opportunities.
 *
 *  The algorithmic complexity (O(n³)) remains unchanged, and the exact
 *  numeric results are identical to the reference implementation.
 */

inline static constexpr int match(int b1, int b2) noexcept {
    /* return 1 if b1+b2==3 (i.e. A–U or C–G), else 0 */
    return (b1 + b2 == 3);
}

/* Helper to convert 2‑D indices to a 1‑D offset into `table`.
 * 0 ≤ i < n, 0 ≤ j < n, and i < j must hold. */
inline static size_t offset(size_t i, size_t j, size_t n) noexcept {
    return i * n + j;
}

/* Main computational kernel. */
void kernel_nussinov(size_t n, const std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    /* Flatten the 2‑D vector to a linear array for better locality. */
    std::vector<int> flat(n * n);
    for (size_t i = 0; i < n; ++i)
        std::copy(table[i].begin(), table[i].end(), flat.begin() + i * n);

    /* Process anti‑diagonals: i + j = d.  d ranges from 1 to 2*(n-1). */
    #pragma omp parallel for schedule(static)
    for (int d = 1; d < 2 * static_cast<int>(n); ++d) {
        /* i starts so that i ≥ 0 and j = d-i < n. */
        size_t i_start = (d < static_cast<int>(n)) ? 0 : d - static_cast<int>(n) + 1;
        size_t i_end   = std::min(d, static_cast<int>(n - 1));

        for (size_t i = i_start; i <= i_end; ++i) {
            size_t j = d - i;
            if (j <= i || j >= n) continue;        // maintain i < j

            size_t idx = offset(i, j, n);
            int best = flat[idx];                  // start with current value

            /* table[i][j-1] */
            if (j > 0)
                best = std::max(best, flat[offset(i, j - 1, n)]);

            /* table[i+1][j] */
            if (i + 1 < n)
                best = std::max(best, flat[offset(i + 1, j, n)]);

            /* table[i+1][j-1] + match(seq[i], seq[j]) */
            if (i + 1 < n && j > 0) {
                int m = match(seq[i], seq[j]);
                int val = flat[offset(i + 1, j - 1, n)] + m;
                best = std::max(best, val);
            }

            /* split at k, i < k < j */
            // Small manual unrolling to reduce loop overhead.
            for (size_t k = i + 1; k < j; ++k) {
                int val = flat[offset(i, k, n)] + flat[offset(k + 1, j, n)];
                if (val > best) best = val;
            }

            flat[idx] = best;
        }
    }

    /* Copy back to the original table representation. */
    for (size_t i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n,
                  table[i].begin());
}
