```cpp
#include <cmath>
#include <vector>
#include <cmath>
#include <cstddef>
#include <omp.h>

/* Optimised kernel_deriche implementation.
 *  - Flattened 2‑D containers to 1‑D for cache friendliness.
 *  - Pre‑computed constants.
 *  - Explicit OpenMP parallel loops over the width dimension.
 *  - Uses single precision floats throughout to reduce memory traffic.
 *  - Maintains identical numerical results to the original.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    const float a = static_cast<float>(alpha);

    /* Pre‑compute constants exactly as in the reference code */
    const float expA  = std::exp(-a);
    const float exp2A = std::exp(-2.f * a);
    const float denom = 1.f + 2.f * a * expA - exp2A;
    const float k = 1.f - expA * (1.f - expA) / denom;

    const float a1 = a5 = k;
    const float a2 = a6 = k * expA * (a - 1.f);
    const float a3 = a7 = k * expA * (a + 1.f);
    const float a4 = a8 = -k * exp2A;
    const float b1 = std::pow(2.f, -a);
    const float b2 = -exp2A;
    const float c1 = 1.f, c2 = 1.f;   // both equal to 1

    /* Flatten the 2‑D containers into 1‑D linear views */
    const std::size_t SZ = static_cast<std::size_t>(w) * h;
    std::vector<float> inS   (SZ), outS(SZ);
    std::vector<float> y1S   (SZ), y2S(SZ);
    std::vector<float> inCol (w), outCol(w);

    /* Copy input into flattened array */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j)
            inS[static_cast<std::size_t>(i) * h + j] = imgIn[i][j];
    }

    /* ---------------------------------------------------------------- */
    /* Forward and backward passes along rows (i direction)            */
    /* ---------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const std::size_t off = static_cast<std::size_t>(i) * h;
        float ym1 = 0.f, ym2 = 0.f, xm1 = 0.f;

        for (int j = 0; j < h; ++j) {
            const float in = inS[off + j];
            const float y  = a1 * in + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1S[off + j] = y;
            xm1 = in;
            ym2 = ym1;
            ym1 = y;
        }

        float yp1 = 0.f, yp2 = 0.f, xp1 = 0.f, xp2 = 0.f;
        for (int j = h - 1; j >= 0; --j) {
            const float xp1_prev = xp1;
            const float xp2_prev = xp2;
            const float yp1_prev = yp1;
            const float yp2_prev = yp2;

            const float y  = a3 * xp1_prev + a4 * xp2_prev + b1 * yp1_prev + b2 * yp2_prev;
            y2S[off + j] = y;
            xp2 = xp1_prev;
            xp1 = inS[off + j];
            yp2 = yp1_prev;
            yp1 = y;
        }
    }

    /* Sum y1 + y2 into outS (clamp to 1‑D array) */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            outS[static_cast<std::size_t>(i) * h + j] = c1 * (y1S[static_cast<std::size_t>(i) * h + j] +
                                                            y2S[static_cast<std::size_t>(i) * h + j]);

    /* ---------------------------------------------------------------- */
    /* Forward and backward passes along columns (j direction)         */
    /* ---------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.f, ym1 = 0.f, ym2 = 0.f;
        for (int i = 0; i < w; ++i) {
            const float in = outS[static_cast<std::size_t>(i) * h + j];
            const float y  = a5 * in + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1S[static_cast<std::size_t>(i) * h + j] = y;
            tm1 = in;
            ym2 = ym1;
            ym1 = y;
        }
    }

#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.f, tp2 = 0.f, yp1 = 0.f, yp2 = 0.f;
        for (int i = w - 1; i >= 0; --i) {
            const float tp1_prev = tp1;
            const float tp2_prev = tp2;
            const float yp1_prev = yp1;
            const float yp2_prev = yp2;

            const float y  = a7 * tp1_prev + a8 * tp2_prev + b1 * yp1_prev + b2 * yp2_prev;
            y2S[static_cast<std::size_t>(i) * h + j] = y;
            tp2 = tp1_prev;
            tp1 = outS[static_cast<std::size_t>(i) * h + j];
            yp2 = yp1_prev;
            yp1 = y;
        }
    }

    /* Final sum into outS (c2 = 1) */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            outS[static_cast<std::size_t>(i) * h + j] = c2 * (y1S[static_cast<std::size_t>(i) * h + j] +
                                                             y2S[static_cast<std::size_t>(i) * h + j]);

    /* Copy result back to 2‑D output vector */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = outS[static_cast<std::size_t>(i) * h + j];
}
