```cpp
#include <vector>
#include <cmath>
#include <cstddef>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return.  */
void kernel_adi(
        int tsteps, int n,
        std::vector<std::vector<double>>& u,
        std::vector<std::vector<double>>& v,
        std::vector<std::vector<double>>& p,
        std::vector<std::vector<double>>& q)
{
    const double DX = 1.0 / static_cast<double>(n);
    const double DY = 1.0 / static_cast<double>(n);
    const double DT = 1.0 / static_cast<double>(tsteps);
    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    /* local aliases for faster row access */
    std::vector<double*> urow(n), vrow(n), prow(n), qrow(n);
    for (int i = 0; i < n; ++i)
    {
        urow[i] = u[i].data();
        vrow[i] = v[i].data();
        prow[i] = p[i].data();
        qrow[i] = q[i].data();
    }

    /* Main time‑stepping loop */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* 1st directional sweep */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* vp0 = vrow[0];
            double* pv0 = prow[i];
            double* pq0 = qrow[i];

            vp0[i] = 1.0;          /* v[0][i] = 1.0           */
            pv0[0] = 0.0;          /* p[i][0] = 0.0           */
            pq0[0] = vp0[i];       /* q[i][0] = v[0][i]       */

            /* Forward elimination (j = 1 … n-2) */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = a * pv0[j - 1] + b;
                pv0[j] = -c / denom;

                double denom2 = a * pv0[j - 1] + b;   // same as denom
                double num    = (-d * urow[j][i - 1]
                                 + (1.0 + 2.0 * d) * urow[j][i]
                                 - f * urow[j][i + 1]
                                 - a * pq0[j - 1]);

                pq0[j] = num / denom2;
            }

            vrow[n - 1][i] = 1.0;   /* v[n‑1][i] = 1.0       */

            /* Backward sweep (j = n-2 … 1) */
            for (int j = n - 2; j >= 1; --j)
                vrow[j][i] = pv0[j] * vrow[j + 1][i] + pq0[j];
        }

        /* 2nd directional sweep */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* up0 = urow[0];
            double* pu0 = prow[i];
            double* pq0 = qrow[i];

            up0[i] = 1.0;          /* u[0][i] = 1.0           */
            pu0[0] = 0.0;          /* p[i][0] = 0.0           */
            pq0[0] = up0[i];       /* q[i][0] = u[0][i]       */

            /* Forward elimination (j = 1 … n-2) */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = d * pu0[j - 1] + e;
                pu0[j] = -f / denom;

                double denom2 = d * pu0[j - 1] + e; // same as denom
                double num    = (-a * vrow[i - 1][j]
                                 + (1.0 + 2.0 * a) * vrow[i][j]
                                 - c * vrow[i + 1][j]
                                 - d * pq0[j - 1]);

                pq0[j] = num / denom2;
            }

            urow[n - 1][i] = 1.0;   /* u[n‑1][i] = 1.0        */

            /* Backward sweep (j = n-2 … 1) */
            for (int j = n - 2; j >= 1; --j)
                urow[j][i] = pu0[j] * urow[j + 1][i] + pq0[j];
        }
    }
}
